<template v-if="diseaseVar == 'all' && isDataLoaded">
  <div class="grid grid-cols-2 gap-10 max-w-[1200px] mx-auto my-2">
    <div v-if="isDataLoaded" class="chart-container flex flex-col gap-5">
        <!-- Adjust mb of title paragraphs for vertical alignment -->
        <p class="italic "> Number of patients in database </p>
        <VuePlotly :data="barCaseCount" :layout="barLayout"></VuePlotly>
    </div>
    <div v-if="isDataLoaded" class="chart-container flex flex-col gap-2">
        <p class="ml-10 italic"> Sex ratio </p>
        <VuePlotly :data="barSexRatio" :layout="barLayout"></VuePlotly>
    </div>
    <div v-if="isDataLoaded" class="chart-container flex flex-col gap-2">
        <p class="ml-10 italic"> Age at diagnosis (months) </p>
        <VuePlotly :data="boxAgeAtDiag" :layout="boxLayout"></VuePlotly>
    </div>
    <div v-if="isDataLoaded" class="chart-container flex flex-col gap-2">
        <p class="ml-10 italic"> Survival (months) </p>
        <VuePlotly :data="survData" :layout="survLayout"></VuePlotly>
    </div>
    <div v-if="isDataLoaded" class="chart-container flex flex-col gap-2">
        <p class="ml-10 italic"> Age at last follow-up (years) </p>
        <VuePlotly :data="boxAgeAtLastFoUp" :layout="boxLayout"></VuePlotly>
    </div>
  </div>
</template>

<template v-if="diseaseVar == 'casecount' && isDataLoaded">
  <div class="grid grid-cols-1 gap-10 max-w-[1200px] mx-auto my-2">
    <div v-if="isDataLoaded" class="chart-container flex flex-col gap-5">
        <!-- Adjust mb of title paragraphs for vertical alignment -->
        <p class="italic "> Number of patients in database </p>
        <VuePlotly :data="barCaseCount" :layout="barLayout"></VuePlotly>
    </div>
  </div>
</template>

<template v-if="diseaseVar == 'sexratio' && isDataLoaded">
  <div class="grid grid-cols-1 gap-10 max-w-[1200px] mx-auto my-2">
    <div v-if="isDataLoaded" class="chart-container flex flex-col gap-2">
        <p class="ml-10 italic"> Sex ratio </p>
        <VuePlotly :data="barSexRatio" :layout="barLayout"></VuePlotly>
    </div>
  </div>
</template>

<template v-if="diseaseVar == 'ageatdiag' && isDataLoaded">
  <div class="grid grid-cols-1 gap-10 max-w-[1200px] mx-auto my-2">
    <div v-if="isDataLoaded" class="chart-container flex flex-col gap-2">
        <p class="ml-10 italic"> Age at diagnosis (months) </p>
        <VuePlotly :data="boxAgeAtDiag" :layout="boxLayout"></VuePlotly>
    </div>
  </div>
</template>

<template v-if="diseaseVar == 'survival' && isDataLoaded">
  <div class="grid grid-cols-1 gap-10 max-w-[1200px] mx-auto my-2">
    <div v-if="isDataLoaded" class="chart-container flex flex-col gap-2">
        <p class="ml-10 italic"> Survival (months) </p>
        <VuePlotly :data="survData" :layout="survLayout"></VuePlotly>
    </div>
  </div>
</template>

<template v-if="diseaseVar == 'ageatlastfoup' && isDataLoaded">
  <div class="grid grid-cols-1 gap-10 max-w-[1200px] mx-auto my-2">
    <div v-if="isDataLoaded" class="chart-container flex flex-col gap-2">
        <p class="ml-10 italic"> Age at last follow-up (years) </p>
        <VuePlotly :data="boxAgeAtLastFoUp" :layout="boxLayout"></VuePlotly>
    </div>
  </div>
</template>



</template>





<script>
import myPatientData from '@/assets/patientData.json'
import mySurvivalData from '@/assets/survivalTemplate1.json'
import mySurvivalLayout from '@/assets/survivalLayout1.json'
import myBarLayout from '@/assets/barLayout.json'
import myBoxLayout from '@/assets/boxLayout.json'
import { VuePlotly } from 'vue3-plotly'


export default {
    name: "DiseaseData",
    components: { 
        VuePlotly 
    },
    data() {
      return this.initialState()
    },
    mounted() { 
        this.reset();
        this.gatherDiseaseData();    
    },
    methods: {
      initialState() {
        return {
            patientData: myPatientData,
            isDataLoaded: false,
            diseaseData: [
               {
                   "omim": "619662",
                   "name": "PFIC8",
                   "patientNo": 0,
                   "girlNo": 0,
                   "birthGA": [],
                   "ageAtDiag": [],
                   "ageAtLastFoUp": [],
                   "bgColor": "#fca5a5"
               },
               {
                   "omim": "619849",
                   "name": "PFIC9",
                   "patientNo": 0,
                   "girlNo": 0,
                   "birthGA": [],
                   "ageAtDiag": [],
                   "ageAtLastFoUp": [],
                   "bgColor": "#e5e5e5"
               },
               {
                   "omim": "211600",
                   "name": "PFIC1",
                   "patientNo": 0,
                   "girlNo": 0,
                   "birthGA": [],
                   "ageAtDiag": [],
                   "ageAtLastFoUp": [],
                   "bgColor": "#38bdf8"
               }
            ],
            barCaseCount: [
                {
                    "x": [],
                    "y": [],
                    "type": "bar",
                    "text": [],
                    "textposition": "auto",
                    "hoverinfo": "none",
                    "marker": {
                      "color": [],
                      "line": {
                        "color": [],
                        "width": 1
                      }
                    }
                }
            ],
            barSexRatio: [
                {
                    "x": [],
                    "y": [],
                    "type": "bar",
                    "text": [],
                    "textposition": "auto",
                    "hoverinfo": "none",
                    "marker": {
                      "color": [],
                      "line": {
                        "color": [],
                        "width": 1
                      }
                    }
                }
            ],
            boxAgeAtDiag: [
                 {
                     "y": [], 
                     "type":"box",
                     "name": "",
                     "line": {"width": 1, "color": "#fca5a5"}
                 },
                 {
                     "y": [], 
                     "type":"box",
                     "name": "",
                     "line": {"width": 1, "color": "#e5e5e5"}
                 },
                 {
                     "y": [], 
                     "type":"box",
                     "name": "",
                     "line": {"width": 1, "color": "#38bdf8"}
                 }
            ],
            boxAgeAtLastFoUp: [
                 {
                     "y": [], 
                     "type":"box",
                     "name": "",
                     "line": {"width": 1, "color": "#fca5a5"}
                 },
                 {
                     "y": [], 
                     "type":"box",
                     "name": "",
                     "line": {"width": 1, "color": "#e5e5e5"}
                 },
                 {
                     "y": [], 
                     "type":"box",
                     "name": "",
                     "line": {"width": 1, "color": "#38bdf8"}
                 }
            ],
            survData: mySurvivalData,
            survLayout: mySurvivalLayout, 
            boxLayout: myBoxLayout, 
            barLayout: myBarLayout 
        }
      },
      reset() {
        Object.assign(this.$data, this.initialState())
      },
      //source for rerendering: https://michaelnthiessen.com/force-re-render/
      gatherDiseaseData() {
          //for each entry in patient data
          this.patientData.forEach(
              patient => {
                  //if required entries are present, increment patient count, increment female count, add GA to array of GAs and add age at first symptoms to corresponding array
                  (patient.omim && this.diseaseData.forEach((element) => (element.omim == patient.omim && element.patientNo++)));    //
                  (patient.omim && patient.sex === 'F' && this.diseaseData.forEach((element) => (element.omim == patient.omim && element.girlNo++)));  // 
                  (patient.omim && patient.term && this.diseaseData.forEach((element) => (element.omim == patient.omim && element.birthGA.push(patient.term))));  // 
                  (patient.omim && patient.firstsymptomagemonth && this.diseaseData.forEach(element => element.omim == patient.omim && element.ageAtDiag.push(patient.firstsymptomagemonth)));  // 
                  (patient.omim && patient.lastnewsageyear && this.diseaseData.forEach(element => element.omim == patient.omim && element.ageAtLastFoUp.push(patient.lastnewsageyear)));  // 
              }
          );
          let i = 0;
          this.diseaseData.forEach((element) => {
               this.barCaseCount[0].x.push(element.name); 
               this.barSexRatio[0].x.push(element.name); 
               this.barCaseCount[0].marker.color.push(element.bgColor + "33");
               this.barCaseCount[0].marker.line.color.push(element.bgColor);
               this.barSexRatio[0].marker.color.push(element.bgColor + "33");
               this.barSexRatio[0].marker.line.color.push(element.bgColor);
               this.boxAgeAtDiag[i].name = element.name;
               this.boxAgeAtLastFoUp[i].name = element.name;
               this.barCaseCount[0].y.push(element.patientNo);
               this.barCaseCount[0].text.push(String(element.patientNo)); 
               this.barSexRatio[0].y.push((element.patientNo - element.girlNo)/element.girlNo); 
               this.barSexRatio[0].text.push(String((element.patientNo - element.girlNo)/element.girlNo)); 
               this.boxAgeAtDiag[i].y = element.ageAtDiag;
               this.boxAgeAtLastFoUp[i].y = element.ageAtLastFoUp;
               ++i;
          });
          this.isDataLoaded = true;
          //Dummy survival data is in days. Convert it to months
          this.survData.forEach(element => element.x = element.x * 0.0329 );
      },
    },
    props: {
    diseaseVar: {
        type: String,
        required: true,
        default: "sexratio" 
        }
    },
}

</script>


